import requests
import json

RABBITMQ_API_URL = 'http://localhost:15672/api'
USERNAME = 'guest'
PASSWORD = 'guest'

def create_vhost(vhost_name):
    url = f"{RABBITMQ_API_URL}/vhosts/{vhost_name}"
    response = requests.put(url, auth=(USERNAME, PASSWORD))
    return response.status_code

def set_permissions(vhost_name, user, permissions):
    url = f"{RABBITMQ_API_URL}/permissions/{vhost_name}/{user}"
    response = requests.put(url, auth=(USERNAME, PASSWORD), data=json.dumps(permissions), headers={'Content-Type': 'application/json'})
    return response.status_code

def main():
    vhosts = {
        'app1_vhost': {
            'user': 'app1_user',
            'permissions': {
                'configure': '.*',
                'write': '.*',
                'read': '.*'
            }
        },
        'app2_vhost': {
            'user': 'app2_user',
            'permissions': {
                'configure': '.*',
                'write': '.*',
                'read': '.*'
            }
        }
    }

    for vhost, config in vhosts.items():
        print(f"Creating vhost: {vhost}")
        create_vhost(vhost)
        
        print(f"Setting permissions for user: {config['user']} on vhost: {vhost}")
        set_permissions(vhost, config['user'], config['permissions'])

if __name__ == "__main__":
    main()